# ── Pre-fetch restore points (dibutuhkan gate-header sebelum render) ─────────
try:
    from patcher import get_backup_list as _get_bak
    _restore_points = _get_bak(max_items=5)
except Exception:
    _restore_points = []
    _bdir_rp = ROOT / "logs" / "backups"
    if _bdir_rp.exists():
        for _rbf in sorted(
            list(_bdir_rp.glob("STV_V*.rar")) + list(_bdir_rp.glob("STV_V*.zip")),
            key=lambda f: f.stat().st_mtime, reverse=True
        )[:5]:
            _restore_points.append({
                "name": _rbf.name, "path": str(_rbf),
                "version": _rbf.stem, "date_str": "",
                "size_mb": round(_rbf.stat().st_size / 1024 / 1024, 2),
            })
_rp_count = len(_restore_points)

# ── HEADER + VERSION BADGE (CSS checkbox — pure CSS toggle, no JS) ─────────────
bear_regime = cycle in ("BEAR_TREND", "WATCHLIST_ONLY")
