# ── RESTORE POINTS — render only (_restore_points fetched above line 204) ─────
# Tampilkan terlepas ada/tidak — jika kosong, beri info cara generate
import base64 as _gate_b64
import streamlit.components.v1 as _gate_comp

st.markdown('<div style="margin-top:2.5rem"></div>', unsafe_allow_html=True)
with st.expander(
    f"◈ RESTORE POINTS — download versi sebelumnya"
    + (f"  ({len(_restore_points)} tersedia)" if _restore_points else "  (belum ada)"),
    expanded=False
):
    st.markdown(
        '<p style="font-family:Share Tech Mono,monospace;font-size:.58rem;color:#8b9ab0">'
        'Extract ke folder Simple Trading V6, replace files, restart Streamlit.<br>'
        '<span style="color:#4b5563">Backup dibuat otomatis setiap kali halaman dibuka (sekali per versi per hari).</span>'
        '</p>',
        unsafe_allow_html=True)

    if not _restore_points:
        st.markdown(
            '<p style="font-family:Share Tech Mono,monospace;font-size:.6rem;color:#6b7280">'
            '⚠ Belum ada backup. Buka ulang halaman ini untuk generate backup versi aktif.<br>'
            'Atau jalankan: <code style="color:#00ff66">python patcher.py backup</code></p>',
            unsafe_allow_html=True)
    else:
        _cols = st.columns(min(len(_restore_points), 4), gap="small")
        for _i, _rp in enumerate(_restore_points):
            with _cols[_i % 4]:
                try:
                    _bpath  = _rp["path"]
                    _b64    = _gate_b64.b64encode(open(_bpath, "rb").read()).decode()
                    _sz     = _rp["size_mb"]
                    _ver    = _rp["version"]
                    _dt     = _rp["date_str"]
                    _nm     = _rp["name"]
                    _is_cur = _rp.get("is_active", False)
                    _label  = f"⬇ {_ver}" + (" ← AKTIF" if _is_cur else "")
                    _sub    = f"{_dt}  {_sz}MB" if _dt else f"{_sz}MB"
                    _gate_comp.html(f"""
                    <style>
                      .rdb{_i}{{font-family:'Share Tech Mono',monospace;font-size:.62rem;
                        background:{'rgba(0,255,102,.04)' if _is_cur else 'rgba(0,255,102,.08)'};
                        border:1px solid {'rgba(0,255,102,.18)' if _is_cur else 'rgba(0,255,102,.3)'};
                        color:{'#6b7280' if _is_cur else '#00ff66'};
                        cursor:{'default' if _is_cur else 'pointer'};
                        border-radius:3px;padding:5px 10px;
                        width:100%;text-align:left;line-height:1.5}}
                      .rdb{_i}:hover{{background:rgba(0,255,102,.14)}}
                      .rdb-sub{_i}{{display:block;font-size:.54rem;color:#6b7280;
                        margin-top:1px}}
                    </style>
                    <button class="rdb{_i}" title="{_nm} · {_sz}MB"
                      onclick="(function(){{
                        {'return;' if _is_cur else ''}
                        var b=atob('{_b64}'),arr=new Uint8Array(b.length);
                        for(var i=0;i<b.length;i++)arr[i]=b.charCodeAt(i);
                        var blob=new Blob([arr],{{type:'application/octet-stream'}});
                        var url=URL.createObjectURL(blob);
                        var a=window.parent.document.createElement('a');
                        a.href=url;a.download='{_nm}';
                        window.parent.document.body.appendChild(a);
                        a.click();
                        setTimeout(function(){{
                          URL.revokeObjectURL(url);
                          window.parent.document.body.removeChild(a);
                        }},200);
                      }})()">{_label}<span class="rdb-sub{_i}">{_sub}</span></button>
                    """, height=52)
                except Exception as _re:
                    st.caption(f"⚠ {_rp.get('name','?')}: {_re}")
